class Solution:
    def numOfPairs(self, nums, target):
        """
        :type nums: List[str]
        :type target: str
        :rtype: int
        """
        count = Counter(nums)
        target_len = len(target)
        pairs = 0

        for i, num in enumerate(nums):
            num_len = len(num)
            if num_len >= target_len:
                continue

            # Find complement
            complement = target[num_len:]
            if complement in count:
                if num == complement:
                    # Same element, count pairs where i != j
                    pairs += count[num] - 1
                else:
                    pairs += count[complement]

        return pairs
